import React, { useState, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import { ROLES } from '../utils/helpers';
import './LoginForm.css'; // Giả sử có file css

const LoginForm = () => {
  const { login } = useContext(AuthContext);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [selectedRole, setSelectedRole] = useState(ROLES.STAFF);

  const handleSubmit = (e) => {
    e.preventDefault();
    // Giả lập login thành công
    login(username, selectedRole);
  };

  return (
    <div className="login-container">
      <form onSubmit={handleSubmit} className="login-form">
        <h2>Đăng Nhập</h2>
        <div className="form-group">
          <label>Tên đăng nhập:</label>
          <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} required />
        </div>
        <div className="form-group">
          <label>Mật khẩu:</label>
          <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
        </div>
        <div className="form-group">
          <label>Vai trò (Giả lập để test):</label>
          <select value={selectedRole} onChange={(e) => setSelectedRole(e.target.value)}>
            <option value={ROLES.STAFF}>Nhân sự (Staff)</option>
            <option value={ROLES.OPERATIONAL_ADMIN}>Operational Admin</option>
            <option value={ROLES.REGULATORY_ADMIN}>Regulatory Admin</option>
            <option value={ROLES.CHIEF_ADMIN}>Chief Admin</option>
          </select>
        </div>
        <button type="submit">Đăng Nhập</button>
      </form>
    </div>
  );
};

export default LoginForm;
